import { describe, expect, it } from 'vitest';
import {
  THOTH_OATH_AUDIT_TOOL,
  THOTH_OATH_CLEAR_TOOL,
  THOTH_OATH_PROPOSE_TOOL,
  createThothOathSelfManagementMcpClient,
  type ThothOathLedgerStore,
  type ThothOathRecord,
} from '../src/thoth-oath-tools';

describe('Thoth oath self-management tools', () => {
  it('programs, audits, and clears oaths with audit preservation', async () => {
    const client = createThothOathSelfManagementMcpClient({
      now: () => 42,
      randomId: (prefix) => `${prefix}_fixed`,
    });

    const tools = await client.listTools();
    expect(tools.map((tool) => tool.function.name)).toEqual([
      THOTH_OATH_PROPOSE_TOOL,
      THOTH_OATH_CLEAR_TOOL,
      THOTH_OATH_AUDIT_TOOL,
    ]);

    const proposed = await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'keep actions non-authoritative',
      scope: 'action',
      consent: 'operator-requested',
      startTick: 2,
      durationTicks: 3,
    });
    expect(proposed.success).toBe(true);
    expect(JSON.stringify(proposed.result)).toContain('oath.proposed');
    expect(JSON.stringify(proposed.result)).toContain('"expiresAt":180042');
    expect(JSON.stringify(proposed.result)).toContain('"startPhase":2');
    expect(JSON.stringify(proposed.result)).toContain('"expiresAtPhase":5');
    expect(JSON.stringify(proposed.result)).toContain(
      'Gnosis.Witnesses.Interfaith.OathStabilityGateWitness.oath_stability_gate_witness',
    );

    const audited = await client.callTool(THOTH_OATH_AUDIT_TOOL, {
      status: 'active',
    });
    expect(JSON.stringify(audited.result)).toContain('activeOathCount":1');

    const cleared = await client.callTool(THOTH_OATH_CLEAR_TOOL, {
      id: 'oath_fixed',
      reason: 'repair complete',
    });
    expect(JSON.stringify(cleared.result)).toContain('oath.cleared');
    expect(JSON.stringify(cleared.result)).toContain('auditPreserved":true');
  });

  it('treats expired oath timers as inactive without erasing the ledger', async () => {
    let now = 100;
    const client = createThothOathSelfManagementMcpClient({
      now: () => now,
      randomId: (prefix) => `${prefix}_fixed`,
    });

    await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'hold only for one tick',
      durationTicks: 1,
    });
    now = 60_101;

    const audited = await client.callTool(THOTH_OATH_AUDIT_TOOL, {
      status: 'expired',
    });
    expect(JSON.stringify(audited.result)).toContain('effectiveStatus":"expired');
    expect(JSON.stringify(audited.result)).toContain('activeOathCount":0');
    expect(JSON.stringify(audited.result)).toContain('remainingMs":0');
  });

  it('blocks runtime clearing for mast-bound oaths', async () => {
    const client = createThothOathSelfManagementMcpClient({
      now: () => 42,
      randomId: (prefix) => `${prefix}_mast`,
    });

    const proposed = await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'stay tied to the mast through the temptation window',
      bindingStrength: 'mast-bound',
      durationTicks: 3,
    });
    expect(proposed.success).toBe(true);
    expect(JSON.stringify(proposed.result)).toContain('"bindingStrength":"mast-bound"');

    const cleared = await client.callTool(THOTH_OATH_CLEAR_TOOL, {
      id: 'oath_mast',
      reason: 'tempted runtime wants out',
    });
    expect(cleared.success).toBe(true);
    expect(JSON.stringify(cleared.result)).toContain('oath.clear.blocked');
    expect(JSON.stringify(cleared.result)).toContain('cannot be cleared');
  });

  it('preserves external source provenance for mast-bound microcontract oaths', async () => {
    const client = createThothOathSelfManagementMcpClient({
      now: () => 42,
      randomId: (prefix) => `${prefix}_microcontract`,
    });

    const proposed = await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'wait before replying | do not feed output back into input',
      scope: 'microcontract:mc-1:parties=You',
      consent: 'double-confirmed:mc-1:2026-05-21T10:01:00.000Z',
      bindingStrength: 'mast-bound',
      source: 'shared-ui.microcontract.double-confirmation',
      sourceId: 'mc-1',
      theoremRef:
        'Gnosis.Witnesses.Interfaith.OathStabilityGateWitness.oath_stability_gate_witness',
      durationTicks: 10,
    });

    expect(proposed.success).toBe(true);
    expect(JSON.stringify(proposed.result)).toContain(
      '"source":"shared-ui.microcontract.double-confirmation"',
    );
    expect(JSON.stringify(proposed.result)).toContain('"sourceId":"mc-1"');

    const audited = await client.callTool(THOTH_OATH_AUDIT_TOOL, {
      status: 'active',
    });
    expect(JSON.stringify(audited.result)).toContain(
      '"source":"shared-ui.microcontract.double-confirmation"',
    );
    expect(JSON.stringify(audited.result)).toContain('"sourceId":"mc-1"');
  });

  it('rejects timers that are not aligned to GnosisTime ticks', async () => {
    const client = createThothOathSelfManagementMcpClient({
      now: () => 100,
      randomId: (prefix) => `${prefix}_fixed`,
    });

    const proposed = await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'misaligned timer should not bind',
      durationMs: 1_000,
    });

    expect(proposed.success).toBe(false);
    expect(proposed.error).toContain('whole GnosisTime minute ticks');
  });

  it('programs aperiodic oath timers through phi-gated GnosisTime phases', async () => {
    const client = createThothOathSelfManagementMcpClient({
      now: () => 0,
      randomId: (prefix) => `${prefix}_fixed`,
    });

    const proposed = await client.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'sample aperiodically without stalling',
      scheduleMode: 'aperiodic',
      aperiodicTheta: 0,
      durationTicks: 2,
    });

    expect(proposed.success).toBe(true);
    expect(JSON.stringify(proposed.result)).toContain('"mode":"aperiodic"');
    expect(JSON.stringify(proposed.result)).toContain('"startPhase":0');
    expect(JSON.stringify(proposed.result)).toContain('"expiresAtPhase":2');
    expect(JSON.stringify(proposed.result)).toContain('"aperiodicStep"');
  });

  it('hydrates and persists the oath ledger through an injected store', async () => {
    let saved: readonly ThothOathRecord[] = [];
    const store: ThothOathLedgerStore = {
      async load() {
        return saved;
      },
      async save(records) {
        saved = records;
      },
    };
    const first = createThothOathSelfManagementMcpClient({
      now: () => 0,
      randomId: (prefix) => `${prefix}_stored`,
      ledgerStore: store,
    });

    await first.callTool(THOTH_OATH_PROPOSE_TOOL, {
      invariant: 'survive session boundary',
      durationTicks: 2,
    });
    expect(saved).toHaveLength(1);

    const second = createThothOathSelfManagementMcpClient({
      now: () => 60_001,
      randomId: (prefix) => `${prefix}_second`,
      ledgerStore: store,
    });
    const audited = await second.callTool(THOTH_OATH_AUDIT_TOOL, {
      status: 'active',
    });

    expect(JSON.stringify(audited.result)).toContain('survive session boundary');
    expect(JSON.stringify(audited.result)).toContain('"kind":"oath.audit"');
    expect(JSON.stringify(audited.result)).toContain('"activeOathCount":1');
  });
});
